import{_ as a,o as n,c as b,j as r,a as p,a1 as t}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"地球Online系列物品","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/地球Online系列物品.md","filePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/地球Online系列物品.md"}'),l={name:"4.资源分区/7.物品与装备/4.奇物/7.系列物品/地球Online系列物品.md"};function i(o,e,s,d,_,c){return n(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"地球online系列物品",tabindex:"-1"},[p("地球Online系列物品 "),r("a",{class:"header-anchor",href:"#地球online系列物品","aria-label":'Permalink to "地球Online系列物品"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调018")])])],-1),t('<h1 id="地球online系列物品-1" tabindex="-1">地球Online系列物品 <a class="header-anchor" href="#地球online系列物品-1" aria-label="Permalink to &quot;地球Online系列物品&quot;">​</a></h1><p>【步枪弓】<br> D+500分<br> 武器<br> 通常而言是一把黑色涂装的步枪，具有7L武器伤害，【高速】5，使用特殊子弹时器械减值-1，装弹数30发，射程150m<br> 具有【无限子弹】特性，并配置一条枪带<br> 你可以用一个标准动作，把枪带当作弓弦，枪身当作弓身，从弹夹里捏出子弹当作箭射出去，虽然看起来更像是弹弓，但使用【弓箭】专业进行检定<br> 具有6L武器伤害，【高速】3，【破甲】1，【双手】，【无限子弹】特性</p><p>【醛基手套】<br> D+500<br> 武器<br> 这是一款实验室用白手套，具有基于天生武器的2点附加成功，上面绘制了如下图案：<br> H-C=O<br> 这代表了一个醛基</p><p>当你装备了此手套后，你可以用一个标准动作用笔给C边上添加一个符号，使其代表不同的醛类，修改符号也是一个标准动作<br> 【甲醛】：你添加一个H，现在你的手套上附带甲醛附魔。<br> 甲醛在石油化工、医药、轻纺、生物化工以及能源、交通运输等行业均有广泛用途，常出现于质量不达标的家具和装修材料中<br> 你使用【智力-手艺-装修/制造家具】的检定获得1个附加成功</p><p>【乙醛】：你添加一个甲基，现在你的手套上附带乙醛附魔<br> 乙醛可用于调配橘子、橙子、苹果、杏子、草莓等水果香精，也可用于葡萄酒、朗姆酒、威士忌等酒用香精<br> 你使用【智力-手艺-调酒】的检定获得1个附加成功</p><p>你也可以改为添加乙基来代表丙醛等等，但是你的化学知识不足以告诉你丙醛有什么用，所以它没有效果</p><p>【骰子锤】<br> C+1000<br> 武器<br> 这把锤子的主体是一个硕大的二十面骰，当你挥舞它攻击时，骰子会自行转动，砸中敌人的一面数字是多少，就能增加对应数目的伤害<br> 至于骰子在转动时锤柄是怎么连接的，你不必在意这么多。<br> 这把锤子有着武器伤害4L，【威猛】3，【重型武器】，【双手】特性</p><p>你使用这把武器进行攻击时，骰一个rd20，这次掷骰不会被任何增减效果影响，但可以被重骰效果影响<br> 你的此次武器伤害获得等同于你的掷骰出目的机运加值<br> 每轮一次，你可以重新投掷rd20并替换原来的结果，无论如何你必须接受新的结果</p><p>【西装锁子甲】<br> D+500<br> 轻甲<br> 从远处看去这只是一间黑色西装，但凑近了观察你就能发现，这其实是被做成西装形状的锁子甲<br> 这是一件5/5的轻甲<br> 穿上后，你每有7点盔甲防御，就获得1点外貌提升</p><p>【荧光迷彩服】<br> D+500<br> 轻甲<br> 这是一件丛林迷彩服，但是上面的花纹经过了荧光处理，视作2/2的轻甲<br> 当你处于夜晚中，你身上的荧光让你便于发现隐藏的敌人，你的【感知-洞察-侦察】检定获得2点附加成功<br> 当你处于白天，你身上的迷彩花纹让你能更好隐藏在暗处，你的【敏捷-隐秘-潜藏】检定获得2点附加成功</p><p>【灵魂菠萝】<br> D+500<br> 奇物<br> 这是一块菠萝形状的金属雕塑，菠萝的每一面都有一个人头像<br> 购买时绑定一种你已有的攻击检定方式，绑定后无法更改</p><p>当你以选定的攻击方式击败一位评级不低于你的敌人后，菠萝会吸收此人的灵魂，并让菠萝上的一个面浮现对应人的头像<br> 这是一个B级的【免疫复活】的效果，你每场影片至多以这种方式捕获一个灵魂</p><p>当你影片结束回到主神空间后，你可以提取菠萝内的灵魂<br> 每个灵魂可以给予你2XP，仅能用于购买属性/技能/专业，或用于造物规则购买灵魂相关资源</p><p>【芯片箭矢】<br> D+500<br> 消耗品<br> 这是一根箭矢，但是箭头用芯片制作，充满了后现代科幻原始部落风格<br> 你可以用一个迅捷动作将其掏出并搭上弓，将其射中并命中后，直到本场景结束你获得如下效果：</p><p>若命中目标是有线直连的设备，你可以骇入它，并且可以同步骇入在同一个局域网下的设备，这是一个D级【网络】效果<br> 若命中目标是机械生物，你可以命令目标做一些对方生活中确实做，但是在某些时段不合时宜的事，这是一个D级【思维控制】效果<br> 若命中目标和科技无关，则箭矢会像个高科技一样爆炸，造成1点不可豁免的【燃烧】不良点数</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',17)])])}const D=a(l,[["render",i]]);export{m as __pageData,D as default};
